package com.hospital.management.validation;
import com.hospital.management.model.Department;import java.util.Set;
public class DepartmentValidator{private static final Set<String> STATUS=Set.of("ACTIVE","INACTIVE");public ValidationResult validate(Department d){ValidationResult r=new ValidationResult();String n=d.getDepartmentName();if(n==null||n.trim().isEmpty())r.addError("departmentName","Department name is required");else if(n.trim().length()<2)r.addError("departmentName","Department name must contain at least 2 characters");else if(n.trim().length()>100)r.addError("departmentName","Department name cannot exceed 100 characters");if(d.getDescription()!=null&&d.getDescription().trim().length()>500)r.addError("description","Description cannot exceed 500 characters");if(d.getLocation()!=null&&d.getLocation().trim().length()>150)r.addError("location","Location cannot exceed 150 characters");if(d.getStatus()==null||!STATUS.contains(d.getStatus()))r.addError("status","Status must be ACTIVE or INACTIVE");return r;}}
